from collections import Counter

def solve(nums: list[int]) -> list[int]:
    freq = Counter(nums)
    nums_sorted = sorted(freq.keys())

    for x in nums_sorted:
        for y in nums_sorted:
            if x < y and freq[x] != freq[y]:
                return [x, y]
    return [-1, -1]
